parameters.text:
=Generate a complete AI image prompt for this blog post:

Title: {{ $json.output.blog_title }}
Initial Image Prompt: {{ $json.output.image_prompt }}

Include all required elements in JSON: logo, background, text_overlay (headline and subheadline), and output settings.
Output only the JSON.

parameters.inputSchema:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "AI Image Prompt Schema",
  "type": "object",
  "properties": {
    "blog_title": {
      "type": "string",
      "description": "Title of the blog post"
    },
    "image_prompt": {
      "type": "string",
      "description": "Initial AI prompt description of the image"
    },
    "ai_image_config": {
      "type": "object",
      "properties": {
        "logo": {
          "type": "object",
          "properties": {
            "file": { "type": "string" },
            "position": { "type": "string" },
            "size_percentage": { "type": "number" },
            "transparent": { "type": "boolean" }
          },
          "required": ["file", "position", "size_percentage", "transparent"]
        },
        "background": {
          "type": "object",
          "properties": {
            "scene": { "type": "string" },
            "mood": { "type": "string" },
            "lighting": { "type": "string" },
            "composition": { "type": "string" },
            "copy_space": { "type": "string" }
          },
          "required": ["scene", "mood", "lighting", "composition", "copy_space"]
        },
        "text_overlay": {
          "type": "object",
          "properties": {
            "headline": {
              "type": "object",
              "properties": {
                "text": { "type": "string" },
                "font": { "type": "string" },
                "style": { "type": "string" },
                "color": { "type": "string" },
                "background_box": { "type": "string" },
                "size_ratio": { "type": "number" }
              },
              "required": ["text", "font", "style", "color", "background_box", "size_ratio"]
            },
            "subheadline": {
              "type": "object",
              "properties": {
                "text": { "type": "string" },
                "font": { "type": "string" },
                "style": { "type": "string" },
                "color": { "type": "string" },
                "size_ratio": { "type": "number" },
                "separator": { "type": "string" }
              },
              "required": ["text", "font", "style", "color", "size_ratio", "separator"]
            }
          },
          "required": ["headline", "subheadline"]
        },
        "output": {
          "type": "object",
          "properties": {
            "format": { "type": "string" },
            "resolution": { "type": "string" }
          },
          "required": ["format", "resolution"]
        }
      },
      "required": ["logo", "background", "text_overlay", "output"]
    }
  },
  "required": ["blog_title", "image_prompt", "ai_image_config"]
}

