return {
  json: {
    url: imageUrl
  }
};

// ── pure-JS HMAC-SHA256 ─────────────────────────────────────────────
function strToBytes(s) {
  const buf = Buffer.from(s, 'utf8');
  return Array.from(buf);
}

function sha256(message, key) {
  const BLOCK = 64;
  function xor(a, b) { return a.map((v, i) => v ^ b[i]); }

  let k = [...key];
  if (k.length > BLOCK) k = sha256raw(k);
  while (k.length < BLOCK) k.push(0);

  const opad = xor(k, Array(BLOCK).fill(0x5c));
  const ipad = xor(k, Array(BLOCK).fill(0x36));

  return sha256raw([...opad, ...sha256raw([...ipad, ...message])]);
}

function sha256raw(data) {
  const K = [
    0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,
    0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,
    0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,
    0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,
    0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,
    0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,
    0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,
    0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2
  ];
  let [h0,h1,h2,h3,h4,h5,h6,h7] = [
    0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,
    0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19
  ];

  const msg = [...data, 0x80];
  while (msg.length % 64 !== 56) msg.push(0);
  const bitLen = data.length * 8;
  for (let i = 7; i >= 0; i--) msg.push((bitLen / Math.pow(2, i * 8)) & 0xff);

  for (let i = 0; i < msg.length; i += 64) {
    const w = [];
    for (let j = 0; j < 16; j++)
      w[j] = (msg[i+j*4]<<24)|(msg[i+j*4+1]<<16)|(msg[i+j*4+2]<<8)|msg[i+j*4+3];
    for (let j = 16; j < 64; j++) {
      const s0 = rotr(w[j-15],7)^rotr(w[j-15],18)^(w[j-15]>>>3);
      const s1 = rotr(w[j-2],17)^rotr(w[j-2],19)^(w[j-2]>>>10);
      w[j] = (w[j-16]+s0+w[j-7]+s1) >>> 0;
    }
    let [a,b,c,d,e,f,g,h] = [h0,h1,h2,h3,h4,h5,h6,h7];
    for (let j = 0; j < 64; j++) {
      const S1 = rotr(e,6)^rotr(e,11)^rotr(e,25);
      const ch = (e&f)^(~e&g);
      const t1 = (h+S1+ch+K[j]+w[j]) >>> 0;
      const S0 = rotr(a,2)^rotr(a,13)^rotr(a,22);
      const maj = (a&b)^(a&c)^(b&c);
      const t2 = (S0+maj) >>> 0;
      [h,g,f,e,d,c,b,a] = [g,f,e,(d+t1)>>>0,c,b,a,(t1+t2)>>>0];
    }
    h0=(h0+a)>>>0; h1=(h1+b)>>>0; h2=(h2+c)>>>0; h3=(h3+d)>>>0;
    h4=(h4+e)>>>0; h5=(h5+f)>>>0; h6=(h6+g)>>>0; h7=(h7+h)>>>0;
  }
  return [h0,h1,h2,h3,h4,h5,h6,h7].flatMap(h => [h>>>24,(h>>>16)&0xff,(h>>>8)&0xff,h&0xff]);
}

function rotr(x, n) { return (x >>> n) | (x << (32 - n)); }

// ── JWT builder ────────────────────────────────────────────────────
function b64url(str) {
  return Buffer.from(str, 'utf8')
    .toString('base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

function b64urlBytes(bytes) {
  return Buffer.from(bytes)
    .toString('base64')
    .replace(/=/g, '').replace(/\+/g, '-').replace(/\//g, '_');
}

const apiKey = '69a97842d52201b1f5fbbdcb:34a0778304bc7ed6a06994247771af3b12ae21accd5c38a0e979827c265edef9'; // 👈 replace this
const [kid, secret] = apiKey.split(':');
const now = Math.floor(Date.now() / 1000);

const header  = b64url(JSON.stringify({ alg: 'HS256', typ: 'JWT', kid }));
const payload = b64url(JSON.stringify({ iat: now, exp: now + 300, aud: '/admin/' }));
const signingInput = `${header}.${payload}`;

// Hex-decode secret
const secretBytes = secret.match(/.{1,2}/g).map(b => parseInt(b, 16));

// Sign using pure-JS HMAC-SHA256
const msgBytes = strToBytes(signingInput);
const sigBytes = sha256(msgBytes, secretBytes);

const token = `${signingInput}.${b64urlBytes(sigBytes)}`;

return [{ json: { token } }];
